import{_ as e,o as l,c as i,a2 as t}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"收不到短信验证码","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/sms-code.md","filePath":"zh-CN/troubleshooting/sms-code.md"}'),o={name:"troubleshooting/sms-code.md"};function r(h,a,s,n,d,u){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="收不到短信验证码" tabindex="-1">收不到短信验证码 <a class="header-anchor" href="#收不到短信验证码" aria-label="Permalink to &quot;收不到短信验证码&quot;">​</a></h1><p>当无法收到短信验证码时，请按以下顺序逐步排查，绝大多数情况可以解决。</p><h2 id="第一步-刷新手机网络信号" tabindex="-1">第一步：刷新手机网络信号 <a class="header-anchor" href="#第一步-刷新手机网络信号" aria-label="Permalink to &quot;第一步：刷新手机网络信号&quot;">​</a></h2><p>短暂开启手机的飞行模式，等待约 10 秒后关闭，重新连接网络后重试获取验证码。</p><h2 id="第二步-检查短信拦截设置" tabindex="-1">第二步：检查短信拦截设置 <a class="header-anchor" href="#第二步-检查短信拦截设置" aria-label="Permalink to &quot;第二步：检查短信拦截设置&quot;">​</a></h2><p>部分安全管理类 App 或手机系统会误拦截验证码短信，请检查：</p><ul><li>手机内置的骚扰拦截或垃圾信息文件夹</li><li>第三方安全软件（如手机管家、360 卫士等）的短信拦截记录</li></ul><h2 id="第三步-检查手机存储与-sim-卡状态" tabindex="-1">第三步：检查手机存储与 SIM 卡状态 <a class="header-anchor" href="#第三步-检查手机存储与-sim-卡状态" aria-label="Permalink to &quot;第三步：检查手机存储与 SIM 卡状态&quot;">​</a></h2><ul><li>短信存储已满：清理收件箱中不必要的短信</li><li>SIM 卡故障：尝试将手机卡插入另一部手机接收，判断是否为卡槽问题</li><li>SIM 卡氧化：取出手机卡，用清洁软布擦拭芯片后重新插入</li></ul><h2 id="第四步-确认手机话费与停机状态" tabindex="-1">第四步：确认手机话费与停机状态 <a class="header-anchor" href="#第四步-确认手机话费与停机状态" aria-label="Permalink to &quot;第四步：确认手机话费与停机状态&quot;">​</a></h2><p>因欠费停机后，缴费复机 24 小时内可能仍无法正常接收商业短信。确认账户余额充足，如为复机第一天可次日重试。</p><h2 id="第五步-确认所在地网络与运营商状态" tabindex="-1">第五步：确认所在地网络与运营商状态 <a class="header-anchor" href="#第五步-确认所在地网络与运营商状态" aria-label="Permalink to &quot;第五步：确认所在地网络与运营商状态&quot;">​</a></h2><p>所在地区运营商可能出现临时故障。稍等片刻后重试，或询问使用相同运营商的朋友是否有类似问题。</p><h2 id="第六步-检查手机短信接收功能" tabindex="-1">第六步：检查手机短信接收功能 <a class="header-anchor" href="#第六步-检查手机短信接收功能" aria-label="Permalink to &quot;第六步：检查手机短信接收功能&quot;">​</a></h2><p>确认手机没有关闭短信接收功能。查看设置 → 消息设置 → 通知开关是否已开启。</p><h2 id="第七步-重启设备与卡片" tabindex="-1">第七步：重启设备与卡片 <a class="header-anchor" href="#第七步-重启设备与卡片" aria-label="Permalink to &quot;第七步：重启设备与卡片&quot;">​</a></h2><ul><li>重启手机：彻底关机，等待一分钟后重新开机</li><li>重新插拔 SIM 卡：关机后取出 SIM 卡，重新安装牢固后开机</li></ul><h2 id="仍未解决" tabindex="-1">仍未解决 <a class="header-anchor" href="#仍未解决" aria-label="Permalink to &quot;仍未解决&quot;">​</a></h2><p>如完成以上步骤后仍无法收到验证码，请联系客服：</p><ul><li>客服热线：4000712688</li><li>在线客服：在 App 或网站内点击「在线客服」</li></ul><p>如需紧急处理，电话是最快的方式。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/troubleshooting">故障排查</a></li></ul>',23)])])}const b=e(o,[["render",r]]);export{p as __pageData,b as default};
